Dynamically allocated types
• You can malloc() any type; primitive, struct, etc…
• Allows you to make functions that allocate memory / create objects for you!
CMPSC 311 - Introduction to Systems Programming
typedef struct {
double real;
// real component
double imag;
// imaginary component
} complex_t,
complex_t* create_complex(double real, double imag) {
complex_t* newcomp = (complex_t*)malloc(sizeof(complex_t));
if (newcomp == NULL) return NULL;
newcomp->real = real;
newcomp->imag = imag;
  return newcomp;
}
void main(void) {
  complex_t* sqneg1 = create_complex(0, 1);
  sqneg1->real == 0; // evals true
  sqneg1->imag == 1; // evals true
}

